final:
module adc_controller (
    input wire clk,
    input wire reset,
    input wire [23:0] adc_input,
    output reg [23:0] adc_output
);
    reg [23:0] external_buffer;

    always @(posedge clk or posedge reset) begin
        if (reset) begin
            external_buffer <= 24'b0;
        end else begin
            external_buffer <= adc_input;
        end
    end

    always @(external_buffer) begin
        adc_output <= external_buffer;
    end
endmodule
